mapper.select:
select

,k.kecheng_name as kechengName
,c.chapter_name as chapterName
,j.jiaoshi_name as jiaoshiName
from exam a
left join kecheng k on a.kecheng_id = k.id
left join course_chapter c on a.chapter_id = c.id
left join jiaoshi j on a.jiaoshi_id = j.id


        and a.id in

            #{item}



        and a.kecheng_id = #{params.kechengId}


        and a.chapter_id = #{params.chapterId}


        and a.exam_name like concat('%',#{params.examName},'%')


        and a.exam_status = #{params.examStatus}


        and a.jiaoshi_id = #{params.jiaoshiId}


        and a.is_deleted = #{params.isDeleted}


order by a.${params.sort} ${params.order}
